class Solution {
    public int possibleStringCount(String word, int k) {
        int MOD = (int)1e9 + 7;
        int n = word.length();
        int[] dp = new int[n + 1];
        dp[0] = 1;
        int cnt = 1;
        for (int i = 1; i <= n; i++) {
            if (i > 1 && word.charAt(i - 1) == word.charAt(i - 2)) {
                cnt++;
            } else {
                cnt = 1;
            }
            dp[i] = (int)((dp[i - 1] * (cnt + 1)) % MOD);
            if (i >= k) {
                dp[i] = (int)((dp[i] - dp[i - k] + MOD) % MOD);
            }
        }
        return dp[n];
    }
}
